#!/usr/bin/env python3
"""
Prototype transpiler to rewrite CUDA syntax (<<<grid, block>>> launches and __shared__
declarations) into standard C++ calls that invoke functions defined in cucpu.hpp
"""

# todo: get rid of this entire implementation and replace with something more maintainable
import re
import sys


# prelude header:
CUCC_PRELUDE = r"""// =======================
// AUTO-GENERATED BY CUCC, DO NOT EDIT
#include "cucpu.hpp"
#include <array>
using namespace cucpu;

// declarations are re-written by transpiler
#define __global__
#define __device__
#define __host__
#define __forceinline__ inline
#define __restrict__
#define __shared__ 
#define __syncthreads() ::cucpu::syncthreads()
// =======================
"""


def split_top_level_arguments(source_str: str, separator: str = ",") -> list[str]:
    """Splits an expression string by a separator token, ignores instances found
    inside nested scopes like (), [], {}, or <>.

    Args:
        source_str (str): The source code to split
        separator (str, optional): The separator. Defaults to ",".

    Returns:
        list[str]: List of elements that the source was split into
    """
    elements = []
    depth = 0
    current_token = ""
    for c in source_str:
        if c in "([{<":
            depth += 1
        elif c in ")]}>":
            depth -= 1
        if c == separator and depth == 0:
            elements.append(current_token.strip())
            current_token = ""
        else:
            current_token += c
    if current_token.strip():
        elements.append(current_token.strip())

    return elements


def scan_for_kernels(source_code: str) -> dict[str, bool]:
    """Scans source code to construct a dict mapping {kernel_name(str): requires_cooperative_launch(bool)}.
    Analyses the inner body of a matching `__global__` function to evaluate whether it invokes
    synchronisation operations or use shared memory variables.

    Args:
        source_code (str): The source code to create a mapping from

    Returns:
        dict[str, bool]: The mapping
    """
    registry = {}
    # kernel identifies preceding param lists:
    kernel_pattern = re.compile(r"__global__\s+\w[\w:<>,\s\*&]*?\s+(\w+)\s*\(")

    for m in kernel_pattern.finditer(source_code):
        kernel_name = m.group(1)
        body_start_idx = source_code.find("{", m.end())

        if body_start_idx < 0:
            registry[kernel_name] = False
            continue

        # get the body of the function:
        depth = 0
        body_end_idx = body_start_idx
        while body_end_idx < len(source_code):
            if source_code[body_end_idx] == "{":
                depth += 1
            elif source_code[body_end_idx] == "}":
                depth -= 1
                if depth == 0:
                    break
            body_end_idx += 1
        kernel_body = source_code[body_start_idx:body_end_idx]
        needs_coop = ("__syncthreads" in kernel_body) or ("__shared__" in kernel_body)
        registry[kernel_name] = needs_coop

    return registry


def rewrite_shared_memory(source_code: str) -> str:
    """Converts C-style multidimensional __share__ arrays into a per-block shared object
    preserving the C array type. Using a native array type (instead of a std::array), lets
    the reference decay into a pointer (just like real CUDA shared memory), so `int *p = buf`
    works as expected.

    Args:
        source_code (str): The raw source code to convert

    Returns:
        str: The source code with __shared__ arrays transformed into standard C++ code

    Example:
    >>> rewrite_shared_memory("__shared__ float matrix[16][32];")
    auto& matrix = ::cucpu::get_shared_variable<float[16][32]>(1);
    """
    unique_id_counter = 0

    # regex to get datatype, variable label, and array bracket sequence:
    shared_regex = re.compile(
        r"__shared__\s+([\w:\s\*&<>,]+?)\s+(\w+)\s*((?:\[[^\]]*\])*)\s*;"
    )

    def replace_match_handler(m: re.Match) -> str:
        nonlocal unique_id_counter
        base_type, var_name, raw_dims = m.group(1), m.group(2), m.group(3)
        extracted_dims = re.findall(r"\[([^\]]*)\]", raw_dims)
        unique_id_counter += 1
        array_suffix = "".join(f"[{d}]" for d in extracted_dims)
        cpp_type = f"{base_type.strip()}{array_suffix}"
        return f"auto& {var_name} = ::cucpu::get_shared_variable<{cpp_type}>({unique_id_counter});"

    return shared_regex.sub(replace_match_handler, source_code)


def rewrite_kernel_launches(source_code: str, kernel_registry: dict[str, bool]) -> str:
    """Transforms custom CUDA kernel executions into standard C++ calls

    Args:
        source_code (str): The CUDA source code
        kernel_registry (dict[str, bool]): Dict from output of scan_for_kernels function

    Returns:
        str: The C++ standard compliant code
    """
    transformed_fragments = []
    current_index = 0
    identifier_tail_regex = re.compile(r"[A-Za-z_]\w*$")

    while True:
        launch_bracket_idx = source_code.find("<<<", current_index)
        if launch_bracket_idx < 0:
            transformed_fragments.append(source_code[current_index:])
            break

        preceded_text = source_code[current_index:launch_bracket_idx]
        match_tail = identifier_tail_regex.search(preceded_text.rstrip())
        if not match_tail:
            transformed_fragments.append(
                source_code[current_index : launch_bracket_idx + 3]
            )
            current_index = launch_bracket_idx + 3
            continue

        kernel_name = match_tail.group(0)
        prefix_without_kernel = preceded_text.rstrip()[: match_tail.start()]
        transformed_fragments.append(prefix_without_kernel)

        # isolate the boundaries of the execution parameters configuration
        closing_bracket_idx = source_code.find(">>>", launch_bracket_idx + 3)
        configuration_parameters = source_code[
            launch_bracket_idx + 3 : closing_bracket_idx
        ]
        split_config = split_top_level_arguments(configuration_parameters)
        grid_config = split_config[0] if len(split_config) > 0 else "1"
        block_config = split_config[1] if len(split_config) > 1 else "1"

        # advance beyond the configuration tail to isolate function params:
        argument_scan_idx = closing_bracket_idx + 3
        while (
            argument_scan_idx < len(source_code)
            and source_code[argument_scan_idx] in " \t\n"
        ):
            argument_scan_idx += 1

        # scan forward to collect balanced argument block parens:
        nesting_depth = 0
        argument_end_idx = argument_scan_idx
        while argument_end_idx < len(source_code):
            if source_code[argument_end_idx] == "(":
                nesting_depth += 1
            elif source_code[argument_end_idx] == ")":
                nesting_depth -= 1
                if nesting_depth == 0:
                    break
            argument_end_idx += 1

        extracted_arguments = source_code[
            argument_scan_idx + 1 : argument_end_idx
        ].strip()

        # route choice mapping back onto either cooperative or fast engine patterns
        target_engine = (
            "launch_cooperative"
            if kernel_registry.get(kernel_name, True)
            else "launch_fast"
        )

        # construct standard c++ call:
        constructed_call = (
            f"::cucpu::{target_engine}({kernel_name}, {grid_config}, {block_config}"
        )
        if extracted_arguments:
            constructed_call += f", {extracted_arguments}"
        constructed_call += ")"

        transformed_fragments.append(constructed_call)
        current_index = argument_end_idx + 1
    return "".join(transformed_fragments)


def transpile_source(raw_source: str) -> str:
    kernel_registry = scan_for_kernels(raw_source)
    processed_source = rewrite_shared_memory(raw_source)
    processed_source = rewrite_kernel_launches(processed_source, kernel_registry)
    return CUCC_PRELUDE + processed_source


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python3 transpiler.py <input_file.cu> [output_file.cpp]")
        sys.exit(1)
    input_path = sys.argv[1]
    output_path = sys.argv[2] if len(sys.argv) > 2 else "/dev/stdout"

    with open(input_path, "r") as iff:
        raw_source = iff.read()

    with open(output_path, "w") as off:
        off.write(transpile_source(raw_source))
